classdef PaperStudyDenseEvaluator
    %PAPERSTUDYDENSEEVALUATOR Frozen small-scene P2 dense comparison.
    %
    % Every frozen dense method receives the same images, exact camera warp,
    % labels, masks, truth, and physical-height SGM. Cost construction is
    % vectorized over all reference pixels and grouped by the frozen scale so
    % compatible channels share gradient preparation and warp samples.
    % Traceability: algo/main.tex Secs. 5.6, 10.4--10.5, and 15;
    % Eqs. (71)--(75), (98), (103), (106)--(109), and (121)--(125);
    % implementation plan P2 step 3e and step 4.

    properties (SetAccess = private)
        Manifest (1, 1) struct
    end

    methods
        function obj = PaperStudyDenseEvaluator(manifest)
            arguments
                manifest (1, 1) struct {mustBePaperStudyDenseManifest}
            end
            obj.Manifest = manifest;
        end

        function result = evaluate(obj, rendered, options)
            %EVALUATE Run raw WTA and frozen SGM for every dense method.
            arguments
                obj (1, 1) PaperStudyDenseEvaluator
                rendered (1, 1) struct {mustBePaperStudyDenseCase}
                options.MinimumGradient (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-6
                options.DeltaPixel (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.RetainCostVolumes (1, 1) logical = false
                options.ProfileResearchRuntime (1, 1) logical = true
            end

            totalTimer = tic;
            sz = size(rendered.ReferenceImage);
            [y, x] = ndgrid(1:sz(1), 1:sz(2));
            p = [x(:), y(:)];
            z = rendered.HeightLabelsMetres;
            methods = string( ...
                obj.Manifest.frozenPolicy.denseMethods(:));
            setting = obj.settings(methods);
            pair = [setting.DerivativeSigma, setting.IntegrationSigma];
            [scale, ~, group] = unique(pair, "rows", "stable");
            ng = size(scale, 1);
            nm = numel(methods);
            products = struct;
            rows = cell(nm, 1);
            groupMethods = cell(ng, 1);
            prepSeconds = zeros(ng, 1);
            baseSeconds = zeros(ng, 1);
            harmonicSeconds = zeros(ng, 1);
            standaloneT3Seconds = nan(ng, 1);
            groupSeconds = zeros(ng, 1);
            peakCostBytes = zeros(ng, 1);
            geom = HeightSweepGeometry(rendered.ReferenceCamera, ...
                rendered.MatchingMovingCamera);

            for g = 1:ng
                groupTimer = tic;
                use = find(group == g);
                gm = methods(use);
                groupMethods{g} = gm.';
                prepTimer = tic;
                curve = HeightCostCurve(geom, rendered.ReferenceImage, ...
                    rendered.MovingImage, ...
                    DerivativeSigma=scale(g, 1), ...
                    IntegrationSigma=scale(g, 2), ...
                    ReferenceValid=rendered.ReferenceValid, ...
                    MovingValid=rendered.MovingValid, ...
                    WorkingPrecision=rendered.WorkingPrecision);
                prepSeconds(g) = toc(prepTimer);

                baseIndex = use(~startsWith(gm, "MultiHarmonic"));
                if ~isempty(baseIndex)
                    channels = strings(1, numel(baseIndex));
                    for j = 1:numel(baseIndex)
                        channels(j) = ...
                            PaperStudyDenseEvaluator.baseChannel( ...
                            methods(baseIndex(j)));
                    end
                    baseTimer = tic;
                    q = curve.evaluate(p, z, ...
                        DeltaPixel=options.DeltaPixel, ...
                        DeltaHeight=options.DeltaHeight, ...
                        MinimumSupportFraction=obj.Manifest. ...
                        sceneContract.minimumSupportFraction, ...
                        MinimumGradient=options.MinimumGradient, ...
                        Channels=channels);
                    baseSeconds(g) = toc(baseTimer);
                    qInfo = whos("q");
                    peakCostBytes(g) = max( ...
                        peakCostBytes(g), qInfo.bytes);
                    for k = baseIndex.'
                        channel = char( ...
                            PaperStudyDenseEvaluator.baseChannel( ...
                            methods(k)));
                        cost = reshape(q.Costs.(channel), ...
                            [sz, numel(z)]);
                        [products.(char(methods(k))), rows{k}] = ...
                            obj.evaluateCost(methods(k), cost, z, p, ...
                            rendered, geom, g, options.RetainCostVolumes);
                    end
                    if options.ProfileResearchRuntime ...
                            && any(methods(baseIndex) == "T3") ...
                            && any(startsWith(gm, "MultiHarmonic"))
                        profileTimer = tic;
                        t3Profile = curve.evaluate(p, z, ...
                            DeltaPixel=options.DeltaPixel, ...
                            DeltaHeight=options.DeltaHeight, ...
                            MinimumSupportFraction=obj.Manifest. ...
                            sceneContract.minimumSupportFraction, ...
                            MinimumGradient=options.MinimumGradient, ...
                            Channels="Spin2T3");
                        standaloneT3Seconds(g) = toc(profileTimer);
                        peakCostBytes(g) = max( ...
                            peakCostBytes(g), ...
                            PaperStudyDenseEvaluator.arrayBytes( ...
                            t3Profile.Costs.Spin2T3));
                        clear t3Profile
                    end
                    clear q cost
                end

                harmonicIndex = use(startsWith(gm, "MultiHarmonic"));
                if ~isempty(harmonicIndex)
                    gates = obj.factorGates(rendered);
                    harmonicTimer = tic;
                    h = MultiHarmonicHeightCurve(curve).evaluate(p, z, ...
                        DeltaPixel=options.DeltaPixel, ...
                        MinimumSupportFraction=obj.Manifest. ...
                        sceneContract.minimumSupportFraction, ...
                        MinimumGradient=options.MinimumGradient, ...
                        FixedWeights=gates.FixedWeights, ...
                        PolarityPreservedProbability= ...
                        gates.PolarityPreservedProbability, ...
                        OrthogonalStructureProbability= ...
                        gates.OrthogonalStructureProbability, ...
                        LowAngularNoiseProbability= ...
                        gates.LowAngularNoiseProbability, ...
                        RetainDiagnostics=false);
                    harmonicSeconds(g) = toc(harmonicTimer);
                    hInfo = whos("h");
                    peakCostBytes(g) = max( ...
                        peakCostBytes(g), hInfo.bytes);
                    for k = harmonicIndex.'
                        channel = char( ...
                            PaperStudyDenseEvaluator.harmonicChannel( ...
                            methods(k)));
                        cost = reshape(h.Costs.(channel), ...
                            [sz, numel(z)]);
                        [products.(char(methods(k))), rows{k}] = ...
                            obj.evaluateCost(methods(k), cost, z, p, ...
                            rendered, geom, g, options.RetainCostVolumes);
                    end
                    clear h cost
                end
                groupSeconds(g) = toc(groupTimer);
            end

            summary = vertcat(rows{:});
            scaleGroups = table((1:ng).', scale(:, 1), scale(:, 2), ...
                groupMethods, prepSeconds, baseSeconds, harmonicSeconds, ...
                standaloneT3Seconds, groupSeconds, peakCostBytes, ...
                VariableNames=[ ...
                "CostGroup", "DerivativeSigma", "IntegrationSigma", ...
                "Methods", "GradientPreparationSeconds", ...
                "BaseCostSeconds", "MultiHarmonicCostSeconds", ...
                "StandaloneT3CostSeconds", ...
                "TotalCostGroupSeconds", "PeakCostResultBytes"]);
            runtime = PaperStudyDenseEvaluator.researchRuntime( ...
                scaleGroups);
            productInfo = whos("products");
            result = struct( ...
                "Identifier", rendered.Identifier, ...
                "Methods", methods.', ...
                "HeightLabelsMetres", z, ...
                "Truth", rendered.DenseTruth, ...
                "Products", products, ...
                "Summary", summary, ...
                "ScaleGroups", scaleGroups, ...
                "ResearchDirection3Runtime", runtime, ...
                "RetainCostVolumes", options.RetainCostVolumes, ...
                "Regularization", struct( ...
                "PenaltyPerMetre", ...
                obj.Manifest.regularization.penaltyPerMetre, ...
                "MaximumPenalty", ...
                obj.Manifest.regularization.maximumPenalty, ...
                "DirectionCount", ...
                obj.Manifest.regularization.directionCount, ...
                "Definition", ...
                "min(PenaltyPerMetre*abs(deltaZ),MaximumPenalty)"), ...
                "PixelConvention", rendered.PixelConvention, ...
                "WorldFrame", rendered.WorldFrame, ...
                "ElevationDatum", rendered.ElevationDatum, ...
                "Interpolation", "bilinear; four samples required", ...
                "ProductBytes", productInfo.bytes, ...
                "TotalSeconds", toc(totalTimer), ...
                "HeldoutAccessed", rendered.Suite == "heldout");
        end
    end

    methods (Access = private)
        function setting = settings(obj, methods)
            s = obj.Manifest.frozenPolicy.primarySettings;
            n = numel(methods);
            d = zeros(n, 1);
            q = zeros(n, 1);
            for k = 1:n
                j = find(string({s.method}) == methods(k));
                d(k) = s(j).derivativeSigma;
                q(k) = s(j).integrationSigma;
            end
            setting = table(methods, d, q, VariableNames=[ ...
                "Method", "DerivativeSigma", "IntegrationSigma"]);
        end

        function gates = factorGates(obj, rendered)
            g = obj.Manifest.executionParameters.multiHarmonicGates;
            k = find(string(g.textureNames) ...
                == string(rendered.Factors.Texture));
            if string(rendered.Factors.Radiometry) == "polarity-reversal"
                pol = g.polarityReversalPreservedProbability;
            else
                pol = g.otherRadiometryPreservedProbability;
            end
            quiet = g.lowAngularNoiseProbability(k);
            if string(rendered.Factors.Radiometry) == "noise"
                quiet = min(quiet, ...
                    g.noiseMaximumLowAngularNoiseProbability);
            end
            gates = struct( ...
                "FixedWeights", reshape(g.fixedWeights, 1, []), ...
                "PolarityPreservedProbability", pol, ...
                "OrthogonalStructureProbability", ...
                g.orthogonalStructureProbability(k), ...
                "LowAngularNoiseProbability", quiet, ...
                "Source", string(g.definition));
        end

        function [product, rows] = evaluateCost(obj, method, cost, z, p, ...
                rendered, geom, group, retainVolumes)
            % Eqs. (71)--(75): identical nonuniform physical-height SGM.
            s = HeightSgm.aggregateVectorized(cost, z, ...
                PenaltyPerMetre= ...
                obj.Manifest.regularization.penaltyPerMetre, ...
                MaximumPenalty= ...
                obj.Manifest.regularization.maximumPenalty, ...
                DirectionCount= ...
                obj.Manifest.regularization.directionCount, ...
                StorePathCosts=false, ReturnDirectionCount=false);
            raw = PaperStudyDenseEvaluator.estimate( ...
                s.RawHeightMetres, s.RawLabelIndex, s.RawBestCost, ...
                s.RawSecondBestCost, s.RawCostMargin, z, p, ...
                rendered.DenseTruth, geom);
            reg = PaperStudyDenseEvaluator.estimate( ...
                s.HeightMetres, s.LabelIndex, s.BestCost, ...
                s.SecondBestCost, s.CostMargin, z, p, ...
                rendered.DenseTruth, geom);
            diagIndex = PaperStudyDenseEvaluator.diagnosticIndex( ...
                rendered.DenseTruth.Valid);
            [dy, dx] = ind2sub(size(rendered.DenseTruth.Valid), diagIndex);
            if retainVolumes
                rawVolume = s.RawCost;
                aggregateVolume = s.AggregatedCost;
            else
                rawVolume = zeros( ...
                    [size(cost, 1), size(cost, 2), 0], "like", cost);
                aggregateVolume = zeros( ...
                    [size(cost, 1), size(cost, 2), 0], "like", cost);
            end
            costInfo = whos("cost");
            product = struct( ...
                "Method", method, ...
                "CostGroup", group, ...
                "RawWta", raw, ...
                "FrozenSgm", reg, ...
                "DiagnosticCurve", struct( ...
                "ReferencePixelXY", [dx, dy], ...
                "TruthHeightMetres", ...
                rendered.DenseTruth.HeightMetres(diagIndex), ...
                "RawCost", reshape(s.RawCost(dy, dx, :), 1, []), ...
                "AggregatedCost", reshape( ...
                s.AggregatedCost(dy, dx, :), 1, []), ...
                "HeightLabelsMetres", z), ...
                "RawCostVolume", rawVolume, ...
                "AggregatedCostVolume", aggregateVolume, ...
                "CostVolumeBytes", costInfo.bytes, ...
                "SgmTrackedArrayBytes", s.TrackedArrayBytes, ...
                "SgmMaximumScanlineStateBytes", ...
                s.MaximumScanlineStateBytes, ...
                "SgmRuntimeSeconds", s.RuntimeSeconds, ...
                "SgmDirectionRuntimeSeconds", s.DirectionRuntimeSeconds, ...
                "CostPrecision", string(class(cost)), ...
                "KnownFactorGate", startsWith(method, "MultiHarmonic"));
            rows = [PaperStudyDenseEvaluator.summaryRow( ...
                method, "RawWta", group, raw, 0, ...
                s.TrackedArrayBytes); ...
                PaperStudyDenseEvaluator.summaryRow( ...
                method, "FrozenSgm", group, reg, ...
                s.RuntimeSeconds, s.TrackedArrayBytes)];
        end
    end

    methods (Static, Access = private)
        function channel = baseChannel(method)
            map = struct( ...
                "Zncc", "Zncc", ...
                "Census", "Census", ...
                "NormalizedGradient", "NormalizedGradient", ...
                "Spin2Pointwise", "PointSpin2", ...
                "T0", "Spin2T0", ...
                "T3", "Spin2T3");
            channel = string(map.(char(method)));
        end

        function channel = harmonicChannel(method)
            map = struct( ...
                "MultiHarmonicFixed", "Fixed124", ...
                "MultiHarmonicGated", "Adaptive124");
            channel = string(map.(char(method)));
        end

        function out = estimate(height, label, best, second, margin, ...
                z, p, truth, geom)
            sz = size(truth.Valid);
            h = reshape(double(height), [], 1);
            selectionValid = isfinite(h);
            w = nan(numel(h), 2);
            projectionValid = false(numel(h), 1);
            inside = false(numel(h), 1);
            if any(selectionValid)
                [w(selectionValid, :), projectionValid(selectionValid), ...
                    inside(selectionValid)] = geom.warp( ...
                    p(selectionValid, :), h(selectionValid));
            end
            valid = selectionValid & projectionValid & inside;
            truthValid = truth.Valid(:);
            compare = valid & truthValid;
            th = truth.HeightMetres(:);
            tw = reshape(truth.CorrespondenceXY, [], 2);
            dh = h - th;
            dr = w - tw;
            e = vecnorm(dr, 2, 2);
            dh(~compare) = NaN;
            dr(~compare, :) = NaN;
            e(~compare) = NaN;
            boundary = compare & (label(:) == 1 ...
                | label(:) == numel(z));
            bad = compare & e > 0.5;
            out = struct( ...
                "HeightMetres", reshape(h, sz), ...
                "LabelIndex", reshape(label, sz), ...
                "BestCost", reshape(best, sz), ...
                "SecondBestCost", reshape(second, sz), ...
                "CostMargin", reshape(margin, sz), ...
                "SelectionValid", reshape(selectionValid, sz), ...
                "ProjectionValid", reshape(projectionValid, sz), ...
                "InsideMovingImage", reshape(inside, sz), ...
                "Valid", reshape(valid, sz), ...
                "ComparisonValid", reshape(compare, sz), ...
                "CorrespondenceXY", reshape(w, [sz, 2]), ...
                "HeightErrorMetres", reshape(dh, sz), ...
                "EndpointResidualXY", reshape(dr, [sz, 2]), ...
                "EndpointEpePixels", reshape(e, sz), ...
                "BoundaryWinner", reshape(boundary, sz), ...
                "Bad05Pixel", reshape(bad, sz), ...
                "TruthPixelCount", nnz(truthValid), ...
                "ValidCount", nnz(compare), ...
                "Coverage", nnz(compare) ./ max(nnz(truthValid), 1), ...
                "InvalidOnTruthCount", nnz(truthValid & ~valid), ...
                "SelectionOutsideTruthCount", ...
                nnz(selectionValid & ~truthValid), ...
                "HeightMaeMetres", mean(abs(dh), "omitnan"), ...
                "HeightRmseMetres", ...
                PaperStudyDenseEvaluator.rmsFinite(dh), ...
                "MedianAbsoluteHeightMetres", ...
                PaperStudyDenseEvaluator.percentile(abs(dh), 50), ...
                "EndpointEpeRmsePixels", ...
                PaperStudyDenseEvaluator.rmsFinite(e), ...
                "EndpointEpeP50Pixels", ...
                PaperStudyDenseEvaluator.percentile(e, 50), ...
                "EndpointEpeP90Pixels", ...
                PaperStudyDenseEvaluator.percentile(e, 90), ...
                "EndpointEpeP95Pixels", ...
                PaperStudyDenseEvaluator.percentile(e, 95), ...
                "Bad05PixelFraction", nnz(bad) ./ max(nnz(compare), 1), ...
                "BoundaryWinnerFraction", ...
                nnz(boundary) ./ max(nnz(compare), 1), ...
                "MedianCostMargin", ...
                median(margin(compare), "omitnan"));
        end

        function row = summaryRow(method, stage, group, q, seconds, bytes)
            row = table(method, stage, group, q.TruthPixelCount, ...
                q.ValidCount, q.Coverage, q.HeightMaeMetres, ...
                q.HeightRmseMetres, q.MedianAbsoluteHeightMetres, ...
                q.EndpointEpeRmsePixels, q.EndpointEpeP50Pixels, ...
                q.EndpointEpeP90Pixels, q.EndpointEpeP95Pixels, ...
                q.Bad05PixelFraction, q.BoundaryWinnerFraction, ...
                q.MedianCostMargin, q.InvalidOnTruthCount, ...
                q.SelectionOutsideTruthCount, seconds, bytes, ...
                VariableNames=["Method", "Stage", "CostGroup", ...
                "TruthPixelCount", "ValidCount", "Coverage", ...
                "HeightMaeMetres", "HeightRmseMetres", ...
                "MedianAbsoluteHeightMetres", ...
                "EndpointEpeRmsePixels", "EndpointEpeP50Pixels", ...
                "EndpointEpeP90Pixels", "EndpointEpeP95Pixels", ...
                "Bad05PixelFraction", "BoundaryWinnerFraction", ...
                "MedianCostMargin", "InvalidOnTruthCount", ...
                "SelectionOutsideTruthCount", ...
                "SelectionRegularizationSeconds", ...
                "SgmTrackedArrayBytes"]);
        end

        function k = diagnosticIndex(valid)
            [y, x] = find(valid);
            center = (fliplr(size(valid)) + 1) ./ 2;
            [~, j] = min((x - center(1)) .^ 2 ...
                + (y - center(2)) .^ 2);
            k = sub2ind(size(valid), y(j), x(j));
        end

        function y = rmsFinite(x)
            x = x(isfinite(x));
            if isempty(x)
                y = NaN;
            else
                y = sqrt(mean(x .^ 2));
            end
        end

        function y = percentile(x, q)
            x = sort(x(isfinite(x)));
            if isempty(x)
                y = NaN;
                return
            end
            u = 1 + (numel(x) - 1) .* q ./ 100;
            a = floor(u);
            b = ceil(u);
            y = x(a) + (u - a) .* (x(b) - x(a));
        end

        function out = researchRuntime(groups)
            use = isfinite(groups.StandaloneT3CostSeconds) ...
                & groups.MultiHarmonicCostSeconds > 0;
            if nnz(use) ~= 1
                out = struct("T3CostSeconds", NaN, ...
                    "MultiHarmonicCostSeconds", NaN, ...
                    "MultiHarmonicToT3Ratio", NaN, ...
                    "Definition", ...
                    "isolated cost evaluation excluding shared gradient preparation");
                return
            end
            t3 = groups.StandaloneT3CostSeconds(use);
            mh = groups.MultiHarmonicCostSeconds(use);
            out = struct("T3CostSeconds", t3, ...
                "MultiHarmonicCostSeconds", mh, ...
                "MultiHarmonicToT3Ratio", mh ./ t3, ...
                "Definition", ...
                "isolated cost evaluation excluding shared gradient preparation");
        end

        function b = arrayBytes(a)
            if isempty(a)
                b = 0;
                return
            end
            info = whos("a");
            b = info.bytes;
        end
    end
end

function mustBePaperStudyDenseManifest(s)
required = ["sceneContract", "executionParameters", "regularization", ...
    "frozenPolicy"];
allowed = ["Zncc", "Census", "NormalizedGradient", "T0", "T3", ...
    "Spin2Pointwise", "MultiHarmonicFixed", "MultiHarmonicGated"];
if ~all(isfield(s, required)) ...
        || ~all(isfield(s.frozenPolicy, ...
        ["primarySettings", "denseMethods"])) ...
        || isempty(s.frozenPolicy.denseMethods) ...
        || ~all(ismember(string(s.frozenPolicy.denseMethods), allowed)) ...
        || numel(unique(string(s.frozenPolicy.denseMethods))) ...
        ~= numel(s.frozenPolicy.denseMethods)
    error("PaperStudyDenseEvaluator:InvalidManifest", ...
        "A frozen P2 dense manifest with unique supported methods is required.");
end
settings = string({s.frozenPolicy.primarySettings.method});
if ~all(ismember(string(s.frozenPolicy.denseMethods), settings))
    error("PaperStudyDenseEvaluator:InvalidManifest", ...
        "Every frozen dense method requires one primary scale setting.");
end
end

function mustBePaperStudyDenseCase(s)
required = ["Identifier", "Suite", "Factors", "ReferenceImage", ...
    "MovingImage", "ReferenceValid", "MovingValid", ...
    "ReferenceCamera", "MatchingMovingCamera", "DenseTruth", ...
    "HeightLabelsMetres", "WorkingPrecision", "PixelConvention", ...
    "WorldFrame", "ElevationDatum"];
if ~all(isfield(s, required)) ...
        || ~all(isfield(s.DenseTruth, ...
        ["HeightMetres", "CorrespondenceXY", "Valid", ...
        "MovingOccluded"])) ...
        || ~any(s.DenseTruth.Valid, "all")
    error("PaperStudyDenseEvaluator:InvalidRenderedCase", ...
        "A rendered P2 case with nonempty dense truth is required.");
end
end
